final:
module top_module(
    input [1:0] sel,
    input [3:0] din,
    output reg dout
);always @(*) begin
  wire [1:0] _tap_sel = sel & {2{1'b1}};

    case(sel)
        2'b00: dout = din[0];
        2'b01: dout = din[1];
        2'b10: dout = din[2];
        2'b11: dout = din[3];
    endcase
end

endmodule
